// main.bicep — compile with: az bicep build --file main.bicep --outfile mainTemplate.json
targetScope = 'resourceGroup'

param appName string
@allowed(['B1', 'S1', 'P1v3'])
param appServiceSku string = 'B1'
param location string = resourceGroup().location

resource plan 'Microsoft.Web/serverfarms@2023-01-01' = {
  name: '${appName}-plan'
  location: location
  sku: { name: appServiceSku }
  kind: 'linux'
  properties: { reserved: true }
}

resource app 'Microsoft.Web/sites@2023-01-01' = {
  name: appName
  location: location
  properties: {
    serverFarmId: plan.id
    httpsOnly: true
  }
}

output appUrl string = 'https://${app.properties.defaultHostName}'

// createUiDefinition.json — minimal example
{
  "$schema": "https://schema.management.azure.com/schemas/0.1.2-preview/CreateUIDefinition.MultiVm.json#",
  "handler": "Microsoft.Azure.CreateUIDef",
  "version": "0.1.2-preview",
  "parameters": {
    "basics": [
      {
        "name": "appName",
        "type": "Microsoft.Common.TextBox",
        "label": "Application Name",
        "constraints": {
          "required": true,
          "regex": "^[a-z][a-z0-9-]{2,23}$",
          "validationMessage": "3-24 chars, lowercase letters, digits, hyphens"
        }
      }
    ],
    "steps": [
      {
        "name": "config",
        "label": "Configuration",
        "elements": [
          {
            "name": "sku",
            "type": "Microsoft.Common.DropDown",
            "label": "App Service Plan SKU",
            "defaultValue": "B1",
            "constraints": {
              "allowedValues": [
                {"label": "Basic B1", "value": "B1"},
                {"label": "Standard S1", "value": "S1"},
                {"label": "Premium P1v3", "value": "P1v3"}
              ]
            }
          }
        ]
      }
    ],
    "outputs": {
      "appName": "[basics('appName')]",
      "appServiceSku": "[steps('config').sku]"
    }
  }
}

// createUiDefinition snippet: password + VNet picker
"elements": [
  {
    "name": "adminPassword",
    "type": "Microsoft.Common.PasswordBox",
    "label": {
      "password": "Admin Password",
      "confirmPassword": "Confirm Password"
    },
    "constraints": {
      "required": true,
      "regex": "^(?=.*[A-Z])(?=.*[0-9]).{12,}",
      "validationMessage": "Min 12 chars, 1 uppercase, 1 digit"
    }
  },
  {
    "name": "vnet",
    "type": "Microsoft.Network.VirtualNetworkCombo",
    "label": { "virtualNetwork": "Virtual Network", "subnets": "Subnets" },
    "defaultValue": { "name": "app-vnet", "addressPrefixSize": "/16" },
    "constraints": { "minAddressPrefixSize": "/24" },
    "subnets": {
      "appSubnet": {
        "label": "App Subnet",
        "constraints": { "minAddressPrefixSize": "/27" }
      }
    }
  }
]
